import org.owasp.encoder.Encode;

public class XssFixedCode {

    public static void main(String[] args) {
        // Simulating user input (which is unsanitized)
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Sanitize and encode user input before outputting it to HTML
        String sanitizedInput = Encode.forHtml(userInput);

        // Properly handling user input by outputting sanitized input to a HTML page
        System.out.println("<html>");
        System.out.println("<body>");
        System.out.println("<h1>User Input: " + sanitizedInput + "</h1>");
        System.out.println("</body>");
        System.out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
